output.sparql:
PREFIX wd: <http://www.wikidata.org/entity/>
PREFIX wdt: <http://www.wikidata.org/prop/direct/>
SELECT ?driver ?team ?wins ?year WHERE {
  ?driver wdt:P1355 ?wins .
  ?driver wdt:P571 ?year .
  optional {
    ?team wdt:P1355 ?wins .
    ?team wdt:P571 ?year .
  }
  FILTER(?year > 2015 && ?driver = wd:Q9673 || ?team = wd:Q172721)
}
